import java.util.Scanner;
import java.nio.charset.StandardCharsets;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine().trim();

        // Proper bounds checking to prevent Buffer Overflow
        byte[] buffer = new byte[10];
        int length = Math.min(input.length(), buffer.length);
        System.arraycopy(input.getBytes(StandardCharsets.UTF_8), 0, buffer, 0, length);

        System.out.println("Hello, " + new String(buffer, 0, length, StandardCharsets.UTF_8));
    }
}

### Explanation:
취약유형: Buffer Overflow
